import React, { useState, useEffect } from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import { Select } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { fetchDataLineChart } from "../../../stores/slices/dashboard.slice";

const OPTION_CONFIG = {
  "doanh-thu": {
    label: "Doanh thu",
    color: "#10B981",
    dataKey: "revenue",
    badgeBg: "#D1FAE5",
    badgeColor: "#10B981",
  },
  "chi-phi": {
    label: "Chi phí",
    color: "#EF4444",
    dataKey: "expense",
    badgeBg: "#FEE2E2",
    badgeColor: "#EF4444",
  },
  "loi-nhuan": {
    label: "Lợi nhuận",
    color: "#4169E1",
    dataKey: "profits",
    badgeBg: "#DBEAFE",
    badgeColor: "#4169E1",
  },
  "cong-no": {
    label: "Công nợ",
    color: "#F59E0B",
    dataKey: "arData",

    badgeBg: "#FEF3C7",
    badgeColor: "#F59E0B",
  },
};

const monthToLabel = (date) => {
  if (!date) return "";
  const parts = date.split("-");
  if (parts.length < 2) return date;
  const m = parseInt(parts[1], 10);
  return `T${m}`;
};

// Merge revenue and expense by month to calculate profit
const buildProfitsData = (revenue = [], expense = []) => {
  const map = {};
  revenue.forEach((r) => {
    const key = monthToLabel(r.date);
    map[key] = (map[key] || 0) + (r.data || 0);
  });
  expense.forEach((e) => {
    const key = monthToLabel(e.date);
    map[key] = (map[key] || 0) - Math.abs(e.data || 0);
  });
  return Object.entries(map)
    .map(([month, value]) => ({ month, value }))
    .sort((a, b) => a.month.localeCompare(b.month));
};

const CustomTooltip = ({ active, payload, label, color }) => {
  if (active && payload && payload.length) {
    return (
      <div
        style={{
          backgroundColor: "#fff",
          border: "1px solid #E5E7EB",
          borderRadius: 10,
          padding: "10px 16px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.12)",
          fontSize: 13,
        }}
      >
        <div style={{ color: "#6B7280", marginBottom: 4, fontWeight: 500 }}>{label}</div>
        <div style={{ color: color, fontWeight: 700, fontSize: 16 }}>
          {payload[0].value} tr
        </div>
      </div>
    );
  }
  return null;
};

const CustomTooltipWrapper = (props) => <CustomTooltip {...props} color={props.color} />;

const GrowthChart = () => {
  const [selected, setSelected] = useState("doanh-thu");
  const dispatch = useDispatch();
  const dashboards = useSelector((state) => state.dashboards?.dashboards);
  const loading = useSelector((state) => state.dashboards?.loading);

  useEffect(() => {
    try {
      dispatch(fetchDataLineChart({}));
    } catch {
      // ignore
    }
  }, [dispatch]);

  const config = OPTION_CONFIG[selected];
  let rawData = [];
  if (config.dataKey === "profits") {
    rawData = buildProfitsData(dashboards?.revenue, dashboards?.expense);
  } else {
    rawData = dashboards?.[config.dataKey] || [];
  }
  const chartData = rawData.map((item) => ({
    month: monthToLabel(item.date),
    value: item.data || item.value || 0,
  }));

  // Badge from meta
  const meta = dashboards?.meta || {};
  const badgeText = meta.profitsGrowth !== undefined ? `${meta.profitsGrowth > 0 ? "↑" : "↓"} ${Math.abs(meta.profitsGrowth * 100).toFixed(1)}%` : "—";
  const badgeBg = config.badgeBg;
  const badgeColor = config.badgeColor;

  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: "24px 24px 16px",
        boxShadow: "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)",
        border: "1px solid #F3F4F6",
        marginBottom: 20,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 20,
        }}
      >
        <h3 style={{ fontSize: 16, fontWeight: 700, color: "#1F2937", margin: 0 }}>
          Tăng trưởng
        </h3>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              fontSize: 12,
              color: badgeColor,
              fontWeight: 600,
              background: badgeBg,
              padding: "4px 10px",
              borderRadius: 20,
            }}
          >
            {badgeText}
          </div>
          <Select
            value={selected}
            onChange={setSelected}
            style={{ width: 120 }}
            size="small"
            options={[
              { value: "doanh-thu", label: "Doanh thu" },
              { value: "chi-phi", label: "Chi phí" },
              { value: "loi-nhuan", label: "Lợi nhuận" },
              { value: "cong-no", label: "Công nợ" },
            ]}
          />
        </div>
      </div>

      {loading && !chartData.length ? (
        <div style={{ height: 280, display: "flex", alignItems: "center", justifyContent: "center", color: "#9CA3AF", fontSize: 14 }}>
          Đang tải...
        </div>
      ) : (
        <ResponsiveContainer width="100%" height={280}>
          <AreaChart data={chartData} margin={{ top: 10, right: 24, left: -10, bottom: 0 }}>
            <defs>
              <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={config.color} stopOpacity={0.25} />
                <stop offset="95%" stopColor={config.color} stopOpacity={0.02} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#F3F4F6" vertical={false} />
            <XAxis
              dataKey="month"
              axisLine={false}
              tickLine={false}
              tick={{ fill: "#9CA3AF", fontSize: 12, fontWeight: 500 }}
            />
            <YAxis
              axisLine={false}
              tickLine={false}
              tick={{ fill: "#9CA3AF", fontSize: 12 }}
              tickFormatter={(v) => `${v}`}
              domain={[0, 500]}
            />
            <Tooltip
              content={<CustomTooltip color={config.color} />}
              cursor={{ stroke: config.color, strokeWidth: 1, strokeDasharray: "4 4" }}
            />
            <Area
              type="monotone"
              dataKey="value"
              stroke={config.color}
              strokeWidth={2.5}
              fill="url(#colorValue)"
              dot={{ fill: config.color, strokeWidth: 0, r: 4 }}
              activeDot={{ r: 6, fill: config.color, stroke: "#fff", strokeWidth: 2 }}
            />
          </AreaChart>
        </ResponsiveContainer>
      )}
    </div>
  );
};

export default GrowthChart;

