import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { fetchDataLineChart } from "../../../stores/slices/dashboard.slice";
import { TrendingUp, TrendingDown, BarChart3, AlertTriangle } from "lucide-react";

const formatCurrency = (val) => {
  if (!val && val !== 0) return "—";
  const abs = Math.abs(val);
  if (abs >= 1e9) return `${(abs / 1e9).toFixed(1)}B ₫`;
  if (abs >= 1e6) return `${(abs / 1e6).toFixed(1)}M ₫`;
  if (abs >= 1e3) return `${(abs / 1e3).toFixed(0)}K ₫`;
  return `${abs} ₫`;
};

const KPICards = () => {
  const dispatch = useDispatch();
  const dashboards = useSelector((state) => state.dashboards?.dashboards);
  const meta = dashboards?.meta || {};

  useEffect(() => {
    try {
      dispatch(fetchDataLineChart({}));
    } catch {}
  }, [dispatch]);

  const kpiData = [
    {
      id: 1,
      label: "Doanh thu",
      value: formatCurrency(meta.totalRevenue),
      badge: meta.profitsGrowth !== undefined ? `${(meta.profitsGrowth * 100).toFixed(0)}%` : "—",
      type: "positive",
      color: "#10B981",
      gradient: "linear-gradient(135deg, #10B981 0%, #059669 100%)",
      icon: TrendingUp,
    },
    {
      id: 2,
      label: "Chi phí",
      value: formatCurrency(meta.totalExpense),
      badge: "—",
      type: "negative",
      color: "#EF4444",
      gradient: "linear-gradient(135deg, #EF4444 0%, #DC2626 100%)",
      icon: TrendingDown,
    },
    {
      id: 3,
      label: "Lợi nhuận",
      value: formatCurrency(meta.totalProfits),
      badge: meta.profitsGrowth !== undefined ? `${(meta.profitsGrowth * 100).toFixed(0)}%` : "—",
      type: meta.totalProfits >= 0 ? "positive" : "negative",
      color: "#3B82F6",
      gradient: "linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)",
      icon: BarChart3,
    },
    {
      id: 4,
      label: "Công nợ",
      value: formatCurrency(meta.totalAr),
      badge: meta.totalAr < 0 ? "Âm" : "Dương",
      type: meta.totalAr >= 0 ? "negative" : "positive",
      color: "#F59E0B",
      gradient: "linear-gradient(135deg, #F59E0B 0%, #D97706 100%)",
      icon: AlertTriangle,
    },
  ];

  return (
    <div className="row g-3 mb-4">
      {kpiData.map((card) => {
        const Icon = card.icon;
        const BadgeIcon = card.badge.startsWith("-") || card.type === "negative" ? TrendingDown : TrendingUp;
        return (
          <div key={card.id} className="col-12 col-sm-6 col-xl-3">
            <div
              style={{
                background: "#fff",
                borderRadius: 16,
                padding: "20px 20px 18px",
                boxShadow: "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)",
                transition: "all 0.25s ease",
                cursor: "pointer",
                position: "relative",
                overflow: "hidden",
                border: "1px solid #F3F4F6",
                borderLeft: `4px solid ${card.color}`,
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 8px 24px rgba(0,0,0,0.10)";
                e.currentTarget.style.transform = "translateY(-3px)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "0 1px 4px rgba(0,0,0,0.06), 0 2px 8px rgba(0,0,0,0.04)";
                e.currentTarget.style.transform = "translateY(0)";
              }}
            >
              {/* Icon Circle */}
              <div
                style={{
                  width: 48,
                  height: 48,
                  borderRadius: 14,
                  background: card.gradient,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  color: "#fff",
                  marginBottom: 14,
                  boxShadow: `0 4px 12px ${card.color}40`,
                }}
              >
                <Icon size={22} strokeWidth={2} />
              </div>

              {/* Label */}
              <div
                style={{
                  fontSize: 12,
                  color: "#9CA3AF",
                  fontWeight: 600,
                  textTransform: "uppercase",
                  letterSpacing: "0.5px",
                  marginBottom: 6,
                }}
              >
                {card.label}
              </div>

              {/* Value */}
              <div
                style={{
                  fontSize: 22,
                  fontWeight: 800,
                  color: "#1F2937",
                  letterSpacing: "-0.5px",
                  marginBottom: 8,
                }}
              >
                {card.value}
              </div>

              {/* Badge */}
              <div
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 3,
                  padding: "3px 10px",
                  borderRadius: 20,
                  fontSize: 12,
                  fontWeight: 700,
                  background: card.type === "positive" ? "#D1FAE5" : "#FEE2E2",
                  color: card.type === "positive" ? "#059669" : "#DC2626",
                }}
              >
                <BadgeIcon size={10} strokeWidth={2.5} />
                {card.badge.replace("%", "")}%
              </div>

              {/* Decorative watermark */}
              <div
                style={{
                  position: "absolute",
                  right: -5,
                  bottom: -5,
                  opacity: 0.06,
                  color: card.color,
                  transform: "rotate(-15deg)",
                }}
              >
                <Icon size={72} strokeWidth={1} />
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

